INSERT INTO app.courses (id, code, title, status) VALUES ('00000000-0000-0000-0000-000000000001', 'ai-bootcamp', 'AI & LLM Bootcamp', 'active') ON CONFLICT (code) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('788b4413-8a1a-5d4f-9a2f-e581c2fe0914', '00000000-0000-0000-0000-000000000001', 'ai-taxonomy', 'AI Taxonomy', 'Classification of AI levels, from classic rule-based systems to agentic systems.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('29962952-9af7-5eab-b357-5caac614a58e', '00000000-0000-0000-0000-000000000001', 'self-attention', 'Self-Attention Mechanism', 'Core mechanism of Transformer computing similarity between tokens using Q, K, V matrices.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('8debe001-c872-57cd-8ce7-74c3f8654666', '00000000-0000-0000-0000-000000000001', 'transformer-architecture', 'Transformer Architecture', 'Revolutionary deep learning architecture based on self-attention, covering encoder and decoder models.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('a492a9aa-e841-5dad-98fc-7b431a2cb88b', '00000000-0000-0000-0000-000000000001', 'token-economy', 'Token Economy', 'Understanding tokenization, context window limits, and cost/latency trade-offs in LLM API usage.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('1b8ed9fe-60a7-5378-a934-7ff0581a688c', '00000000-0000-0000-0000-000000000001', 'ai-product-lifecycle', 'AI Product Lifecycle', 'The end-to-end process of discovering, statements, building, and deploying human-centered AI products.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('0f028c18-4143-561e-a62e-a80eef0a03e3', '00000000-0000-0000-0000-000000000001', 'solution-levels', 'Rule/Workflow/Agent Selection', 'Decision matrix to choose between Rule-based, Workflow, or Agentic architectures based on task complexity.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('fdd664a8-37b0-5853-a738-8cf2cb9aa5d6', '00000000-0000-0000-0000-000000000001', 'agentic-agent-react', 'ReAct Reasoning Pattern', 'Reasoning and acting loop (Thought-Action-Observation) for autonomous agents.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('e3c7d31d-6488-51c0-9a7b-1b5dd97776d8', '00000000-0000-0000-0000-000000000001', 'tool-calling', 'Tool Calling API', 'How LLMs declare, parse, and execute external tools using structured JSON schemas.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('d5781ffc-f1c6-54d9-929d-8d9f8be92b56', '00000000-0000-0000-0000-000000000001', 'prompt-engineering', 'Prompt Engineering', 'Techniques for guiding LLMs, including system prompts, XML structuring, few-shot learning, and Chain-of-Thought.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('5a4528f9-cebd-5f4b-a167-cf19b619ffa8', '00000000-0000-0000-0000-000000000001', 'context-engineering', 'Context Engineering', 'Strategies to manage context window, mitigate Lost-in-the-Middle phenomenon, and compress history.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('c47460a1-8cd9-5ff8-92b6-febda9fdae6f', '00000000-0000-0000-0000-000000000001', 'ai-product-uncertainty', 'AI Product Uncertainty & UX', 'Designing user experiences that handle LLM uncertainty, precision/recall trade-offs, and graceful failures.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('55147612-216e-59fa-871d-f974d4982f5a', '00000000-0000-0000-0000-000000000001', 'vector-embeddings', 'Vector Embeddings', 'Mathematical representation of text in high-dimensional vector spaces, measured by cosine similarity.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('d26aa4cd-c672-5f7a-ad08-1376cf9fd54e', '00000000-0000-0000-0000-000000000001', 'vector-databases', 'Vector Databases', 'Specialized databases for indexing, storing, and performing fast similarity search on vector embeddings.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('7586876d-e208-5f83-9088-ef03df525ffb', '00000000-0000-0000-0000-000000000001', 'basic-rag', 'Basic RAG Pipeline', 'Retrieval-Augmented Generation basics, including document ingestion, chunking, and context-based prompting.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('7c172602-7587-56ee-9f1c-19fa32e9606e', '00000000-0000-0000-0000-000000000001', 'advanced-rag', 'Advanced RAG Pipelines', 'Advanced techniques such as query transformation, reranking, hybrid search, and semantic caching.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('687073df-0582-5e59-98ff-a23563b2bf6a', '00000000-0000-0000-0000-000000000001', 'multi-agent-architectures', 'Multi-Agent Architectures', 'Designing systems with multiple cooperating agents, routers, and specialized coordinators.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('42af4c3b-ee60-5c60-893f-8325f18fd8ec', '00000000-0000-0000-0000-000000000001', 'data-pipelines-observability', 'Data Pipelines & Observability', 'Data pipelines for ETL operations, logging, and observability of LLM interactions.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('cd70fe89-584b-59cf-b12d-fbe149510033', '00000000-0000-0000-0000-000000000001', 'guardrails-safety', 'AI Guardrails & Safety', 'Input/output validation, prompt injection detection, and content filtering for safe AI deployment.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('243c7a89-f8c1-565d-a593-287064079e0c', '00000000-0000-0000-0000-000000000001', 'cloud-infrastructure-agents', 'Cloud Infrastructure for Agents', 'Deploying agents onto cloud platforms using serverless functions, Docker containers, and scalable backends.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('fe09c2a8-5c56-5df3-9591-8af6f42ec3de', '00000000-0000-0000-0000-000000000001', 'observability-stack', 'LLM Observability Stack', 'Monitoring latency, token usage, cost tracking, and system performance at production scale.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('fffb5ed1-7721-5e36-a326-fe4c3151b844', '00000000-0000-0000-0000-000000000001', 'ai-evaluation', 'AI Evaluation & Benchmarking', 'Constructing golden datasets, LLM-as-a-judge patterns, and quantitative evaluation of AI systems.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
INSERT INTO app.concepts (id, course_id, code, name, description, status) VALUES ('c21834c7-64cf-5b8d-af6a-e8887f8dd3d9', '00000000-0000-0000-0000-000000000001', 't1-d17-prd-pmf', '[T1] PRD & Product-Market Fit', 'Analyzing product requirements and identifying PMF for AI applications.', 'active') ON CONFLICT (course_id, code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description;
